                vrPropsValue: (typeof vrProps !== 'undefined') ? vrProps : '',
                videoKeyValue: (typeof VIDEO_SHOW != 'undefined') ? VIDEO_SHOW.vkey : '',
                playerEnvironmentValue: typeof playerEnvironment != 'undefined' ? playerEnvironment : '',
